import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { SKILLS } from '../data/skills';

const TESTIMONIALS = [
  { name: 'Priya, 14', text: 'I built my first website in 3 weeks!', avatar: '👧', skill: 'Web Dev' },
  { name: 'James, 52', text: 'Finally learning guitar at my own pace.', avatar: '👨', skill: 'Music' },
  { name: 'Sofia, 26', text: 'Got a design job after the UI/UX track.', avatar: '👩', skill: 'UI/UX' },
  { name: 'Arjun, 9', text: 'Cooking with my mom now!', avatar: '👦', skill: 'Cooking' },
];

export default function LandingPage() {
  const navigate = useNavigate();
  const [activeSkill, setActiveSkill] = useState(0);
  const [count, setCount] = useState({ learners: 0, skills: 0, lessons: 0 });

  useEffect(() => {
    const targets = { learners: 50000, skills: 120, lessons: 2400 };
    const duration = 2000;
    const steps = 60;
    let step = 0;
    const timer = setInterval(() => {
      step++;
      const pct = step / steps;
      const ease = 1 - Math.pow(1 - pct, 3);
      setCount({
        learners: Math.floor(targets.learners * ease),
        skills: Math.floor(targets.skills * ease),
        lessons: Math.floor(targets.lessons * ease),
      });
      if (step >= steps) clearInterval(timer);
    }, duration / steps);
    return () => clearInterval(timer);
  }, []);

  return (
    <div style={{ minHeight: '100vh', position: 'relative' }}>
      <div className="orb orb1" /><div className="orb orb2" /><div className="orb orb3" />

      {/* NAV */}
      <nav className="nav">
        <div className="nav-logo">⬡ SkillSphere</div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <button className="btn btn-ghost hide-mobile" onClick={() => navigate('/explore')}>Explore</button>
          <button className="btn btn-outline" onClick={() => navigate('/auth?mode=login')}>Log In</button>
          <button className="btn btn-primary" onClick={() => navigate('/auth')}>Get Started Free →</button>
        </div>
      </nav>

      {/* HERO */}
      <section style={{ maxWidth: 1100, margin: '0 auto', padding: '80px 24px 60px', textAlign: 'center', position: 'relative', zIndex: 1 }}>
        <div className="badge badge-green animate-fadeUp" style={{ marginBottom: 24, display: 'inline-flex' }}>
          <span style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--accent)', animation: 'pulse 2s infinite' }} />
          Now with AI-powered personalized roadmaps
        </div>
        <h1 className="animate-fadeUp delay-1" style={{ fontSize: 'clamp(2.8rem, 7vw, 5.8rem)', fontWeight: 800, marginBottom: 24 }}>
          Learn Any Skill<br /><span className="grad">From A to Z</span>
        </h1>
        <p className="animate-fadeUp delay-2" style={{ fontSize: '1.15rem', color: 'var(--text2)', maxWidth: 600, margin: '0 auto 40px', lineHeight: 1.7 }}>
          SkillSphere gives everyone — from kids to seniors — a personalized A→Z roadmap with live classes, AI tutoring, and a community to grow with.
        </p>
        <div className="animate-fadeUp delay-3" style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap', marginBottom: 60 }}>
          <button className="btn btn-primary btn-lg" onClick={() => navigate('/auth')}>
            Start Learning Free →
          </button>
          <button className="btn btn-outline btn-lg" onClick={() => navigate('/explore')}>
            Explore Skills
          </button>
        </div>

        {/* STATS */}
        <div className="animate-fadeUp delay-4" style={{ display: 'flex', justifyContent: 'center', gap: 60, flexWrap: 'wrap', marginBottom: 80 }}>
          {[
            { val: count.learners.toLocaleString() + '+', label: 'Active Learners' },
            { val: count.skills + '+', label: 'Skills Available' },
            { val: count.lessons.toLocaleString() + '+', label: 'Video Lessons' },
            { val: 'All Ages', label: 'Kids to Seniors' },
          ].map((s, i) => (
            <div key={i} style={{ textAlign: 'center' }}>
              <div style={{ fontFamily: 'Syne', fontSize: '2rem', fontWeight: 800, background: 'linear-gradient(135deg, var(--accent), var(--accent2))', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>{s.val}</div>
              <div style={{ color: 'var(--muted)', fontSize: '0.85rem', marginTop: 4 }}>{s.label}</div>
            </div>
          ))}
        </div>

        {/* SKILL SHOWCASE */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: 12, maxWidth: 900, margin: '0 auto' }}>
          {SKILLS.map((skill, i) => (
            <div key={skill.id}
              onClick={() => { setActiveSkill(i); navigate('/auth'); }}
              style={{
                background: 'var(--surface)', border: `1px solid ${activeSkill === i ? skill.color : 'var(--border)'}`,
                borderRadius: 'var(--radius)', padding: '20px 14px', cursor: 'pointer',
                transition: 'all 0.25s', textAlign: 'center',
                transform: activeSkill === i ? 'translateY(-4px)' : 'none',
                boxShadow: activeSkill === i ? `0 8px 30px ${skill.color}30` : 'none',
                animationDelay: `${i * 0.05}s`
              }}
              onMouseEnter={() => setActiveSkill(i)}
              className="animate-fadeUp"
            >
              <div style={{ fontSize: '2rem', marginBottom: 8 }}>{skill.icon}</div>
              <div style={{ fontFamily: 'Syne', fontWeight: 700, fontSize: '0.85rem', marginBottom: 4 }}>{skill.name}</div>
              <div style={{ fontSize: '0.72rem', color: 'var(--muted)' }}>{skill.totalLessons} lessons</div>
            </div>
          ))}
        </div>
      </section>

      {/* HOW IT WORKS */}
      <section style={{ maxWidth: 1000, margin: '0 auto', padding: '80px 24px', position: 'relative', zIndex: 1 }}>
        <div style={{ textAlign: 'center', marginBottom: 56 }}>
          <h2 style={{ fontSize: 'clamp(1.8rem, 4vw, 3rem)', marginBottom: 12 }}>How SkillSphere Works</h2>
          <p style={{ color: 'var(--text2)', fontSize: '1rem' }}>Your journey from complete beginner to confident expert</p>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: 20 }}>
          {[
            { step: '01', icon: '🎯', title: 'Choose Your Skill', desc: 'Pick from 120+ skills across tech, arts, business, and lifestyle.' },
            { step: '02', icon: '🤖', title: 'Get AI Roadmap', desc: 'Spark, our AI tutor, builds your personalized A→Z learning plan.' },
            { step: '03', icon: '🎥', title: 'Watch Live Classes', desc: 'Learn from curated video lessons at your own pace, anytime.' },
            { step: '04', icon: '🏆', title: 'Earn & Grow', desc: 'Complete milestones, earn XP, badges, and certificates.' },
          ].map((item, i) => (
            <div key={i} className="card" style={{ padding: 28, position: 'relative', overflow: 'hidden' }}>
              <div style={{ position: 'absolute', top: 16, right: 16, fontFamily: 'Syne', fontSize: '3rem', fontWeight: 800, color: 'var(--surface3)', lineHeight: 1 }}>{item.step}</div>
              <div style={{ fontSize: '2.2rem', marginBottom: 14 }}>{item.icon}</div>
              <h3 style={{ fontSize: '1.1rem', marginBottom: 8 }}>{item.title}</h3>
              <p style={{ color: 'var(--text2)', fontSize: '0.88rem', lineHeight: 1.6 }}>{item.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* TESTIMONIALS */}
      <section style={{ maxWidth: 900, margin: '0 auto', padding: '60px 24px 100px', position: 'relative', zIndex: 1 }}>
        <div style={{ textAlign: 'center', marginBottom: 48 }}>
          <h2 style={{ fontSize: 'clamp(1.8rem, 4vw, 2.8rem)', marginBottom: 12 }}>Loved by All Ages</h2>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 16 }}>
          {TESTIMONIALS.map((t, i) => (
            <div key={i} className="card" style={{ padding: 24 }}>
              <div style={{ fontSize: '2rem', marginBottom: 12 }}>{t.avatar}</div>
              <p style={{ color: 'var(--text2)', fontSize: '0.9rem', lineHeight: 1.6, marginBottom: 14 }}>"{t.text}"</p>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
