      {/* CTA SECTION */}
      <section style={{ position: 'relative', zIndex: 1, padding: '0 24px 100px' }}>
        <div style={{ maxWidth: 700, margin: '0 auto', textAlign: 'center', background: 'linear-gradient(135deg, rgba(110,231,183,0.08), rgba(56,189,248,0.08))', border: '1px solid rgba(110,231,183,0.2)', borderRadius: 24, padding: '60px 40px' }}>
          <h2 style={{ fontSize: 'clamp(1.8rem, 4vw, 3rem)', marginBottom: 16 }}>Ready to <span className="grad">Master</span> Your First Skill?</h2>
          <p style={{ color: 'var(--text2)', marginBottom: 32, fontSize: '1rem' }}>Join 50,000+ learners. No credit card needed.</p>
